Action.Str:
try {
    var rawBody = local("http_request_body");

    // 如果想要看是不是收到了内容，可以解除下面这行的注释来测试弹窗
    // flash("原始数据: " + rawBody); 

    var data = JSON.parse(rawBody);

    // 使用 Tasker 专用函数强制写入纯小写的本地变量
    setLocal("ctype", data.type);
    setLocal("cvalue", data.content);

} catch(e) {
    // 如果解析出错了，会在屏幕下方弹窗提示原因
    flash("解析失败报错啦: " + e);
}
